              className="relative text-base border-b-transparent bg-transparent px-0 font-semibold text-muted-foreground shadow-none transition-colors duration-300 ease-out hover:text-foreground data-[state=active]:font-semibold data-[state=active]:text-foreground data-[state=active]:shadow-none data-[state=active]:bg-transparent focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary rounded-lg"
            >
              Code
            </TabsTrigger>
          </TabsList>
        </div>
        <TabsContent
          value="preview"
          className="border border-border/60 flex rounded-2xl focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary"
        >
          <div className="w-full flex items-center justify-center rounded-2xl min-h-[350px] overflow-hidden relative">
            <div className="absolute right-4 top-4 z-50 flex gap-2 flex-row">
              <RestartButton onRestart={handleRestart} />
            </div>
            <React.Fragment key={previewKey}>{children}</React.Fragment>
